import { toggleBodyScrollable,toggleMobileMenuCollapse, toggleMenuButton } from '../../utils'
import { useTranslation, initReactI18next } from 'react-i18next'
import { NavLink } from 'react-router-dom'

import LanguageSwitcher from './LanguageSwitcher/LanguageSwitcher'
import translationEN from './../../locales/en/translation.json'
import translationRU from './../../locales/ru/translation.json'
import MobileMenu from './MobileMenu/MobileMenu'
import logo from '../../assets/design/logo.png'
import i18n from "i18next"
import './Header.css'
import { useRef } from 'react'


const resources = {
    en: {
        translation: translationEN,
    },
    ru:{
        translation: translationRU
    }
}
i18n.use(initReactI18next).init({
    resources,
    lng: "en",
    fallbackLng: "en",
    interpolation: {
      escapeValue: false,
    },
})

function Header(props){
    const { t } = useTranslation();
    const logo = useRef(null)

    const toggleMenu = () =>{
        if(logo.current.classList.contains('header-logo-green'))
            logo.current.classList.toggle('header-logo-white')
        toggleMobileMenuCollapse()
        toggleBodyScrollable()
        toggleMenuButton()
    }

    return(
    <>
        <MobileMenu/>
        <div id={'main-header'} className="header-container">
            <header>
                <button id={'mobile-menu-toggle'} onClick={toggleMenu} className='mobile-menu-toggle-btn'>
                    <div className="toggle-line fst"></div>
                    <div className="toggle-line md"></div>
                    <div className="toggle-line end"></div>
                </button>
                <nav className='header-nav'>
                    <NavLink to={'/'}>{t("home")}</NavLink>
                    <NavLink to={'/about'}>{t("about")}</NavLink>
                    <NavLink to={'/projects'}>{t("projects")}</NavLink>
                    <NavLink to={'/contacts'}>{t("contacts")}</NavLink>
                </nav>
                <LanguageSwitcher className='lng-switcher'/>
                <img ref={logo} className={'header-logo' + ' header-logo-' + props.color}  src={logo} alt="" width="83px" height="83px" draggable='false'/>
            </header>
            <span className="header-title">
                interior <br/> design <br/> studio
            </span>
        </div>
    </>
    )
}

export default Header