import { toggleBodyScrollable, toggleMobileMenuCollapse, toggleMenuButton } from "../../../utils";
import { useTranslation, initReactI18next } from 'react-i18next'
import { NavLink } from 'react-router-dom'

import LanguageSwitcher from "../LanguageSwitcher/LanguageSwitcher";
import translationEN from './../../../locales/en/translation.json'
import translationRU from './../../../locales/ru/translation.json'
import i18n from "i18next";
import './MobileMenu.css'


const resources = {
    en: {
        translation: translationEN,
    },
    ru:{
        translation: translationRU
    }
}
i18n.use(initReactI18next).init({
    resources,
    lng: "en",
    fallbackLng: "en",
    interpolation: {
      escapeValue: false,
    },
})

function handleMobileNavClick(){
    toggleBodyScrollable()
    toggleMobileMenuCollapse()
    toggleMenuButton()
}

function MobileMenu() {
    const { t } = useTranslation();

    return (                 
    <div className="mobile-menu menu-collapsed" id='mobile-menu'>
        <nav className='header-nav-mobile'>
            <NavLink to={'/'} onClick={handleMobileNavClick}>{t("home")}</NavLink>
            <NavLink to={'/about'} onClick={handleMobileNavClick}>{t("about")}</NavLink>
            <NavLink to={'/projects'} onClick={handleMobileNavClick}>{t("projects")}</NavLink>
            <NavLink to={'/contacts'} onClick={handleMobileNavClick}>{t("contacts")}</NavLink>
            <LanguageSwitcher/>
        </nav>
        
    </div> 
);
}

export default MobileMenu;